def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                total = 0
                for b in range(1, a + 5):
                    base = ((ratio - a) ** 6) / (a * b * 1.1 + 1.2)
                    trig = np.sin(ratio * b / (a + 1)) * np.cos(ratio / (b + 1))
                    total += base * trig
                priority += total * np.exp((ratio - 7) / (a + 2))
            priority += np.sin(ratio * 2) ** 3 + np.log1p(ratio) * 4.5
            if bin_cap < item * 0.3:
                priority += 7 * np.sqrt(item / (bin_cap + 0.3)) * np.tanh(ratio)
            else:
                priority += np.exp(-ratio) * 6
        elif 5 < ratio <= 8:
            priority = 0
            for x in range(1, int(np.floor(ratio)) + 5):
                for y in range(1, x + 5):
                    val = np.tanh(((ratio - x) ** 4) * np.cos(ratio * y)) / (y + 1)
                    priority += val * 1.7
            priority += np.log(ratio + 1) * 15 - np.tanh(ratio - 5) * 3
            for k in range(5):
                priority += np.sin(ratio * (i + k)) / (k + 1)
        elif 2 <= ratio <= 5:
            s = 0
            for m in range(1, 20):
                s += ((ratio - 2) ** m) / (m * 2.1) * np.cos(m * ratio * 1.2)
            priority = s * np.cos(10 * ratio) - np.log(ratio + 1) * 8 + np.tanh(3 * (5 - ratio)) * 2
            for t in range(3, 8):
                priority += np.sin(t * ratio * i) * ((ratio - 1.7) ** t)/(t + 1)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 15):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for z in range(1, 7):
                priority += np.sin(z * ratio * i * 0.7) * ((ratio - 0.9) ** z) / z
        elif 0.5 <= ratio < 1:
            s = 0
            for p in range(1, 20):
                s += ((1 - ratio) ** p) / (p * 5)
            priority = s
            if (i * int(item * 1.6)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.45
            else:
                priority /= (np.sqrt(bin_cap + 3) + 3)
            for q in range(1, 8):
                priority += ((1 - ratio) ** q) * np.sin(q * item * 1.5) * 0.6
        elif 0.2 <= ratio < 0.5:
            s = 0
            for r in range(1, 15):
                s += ((0.5 - ratio) ** r) / (r * 4) * np.cos(r * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 5
            for s_ in range(1, 9):
                priority += ((0.5 - ratio) ** s_) / (s_ * 8) * np.cos(item * s_ * 1.4)
        else:
            s = 0
            for w in range(1, 15):
                s += ((0.2 - ratio) ** w) / (w * 6) * np.sin(w * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 9) * np.cos(item * v * 1.2)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (bin_cap + item * i) % 7 == 0:
            priority += np.tanh(ratio * i) * 3.5
        else:
            priority -= np.tanh(ratio / (i + 1)) * 3.5
        priorities[i] = priority
    return priorities
